def solve(data, criteria):
    if not isinstance(data, list) or not isinstance(criteria, dict):
        return None

    cleaned_data = []
    seen = set()

    for item in data:
        key = tuple(item.get(k) for k in criteria.keys())
        if key not in seen:
            seen.add(key)
            cleaned_data.append(item)

    return cleaned_data
